// app/api/cookie/route.js
export async function GET(request) {
  const cookie = request.cookies.get('theme')?.value || 'light';

  const response = NextResponse.next();
  response.cookies.set('theme', cookie === 'light' ? 'dark' : 'light', { path: '/' });

  return Response.json({ currentTheme: cookie });
}

import { NextResponse } from 'next/server';

console.log('Cookies util nümunəsi');

// app/api/headers/route.js
export async function GET(request) {
  const userAgent = request.headers.get('user-agent');
  const auth = request.headers.get('authorization');

  return Response.json({ userAgent, hasAuth: !!auth });
}

console.log('Headers oxumaq nümunəsi');

// app/api/redirect/route.js
import { NextResponse } from 'next/server';

export async function GET() {
  return NextResponse.redirect(new URL('/dashboard', request.url));
}

console.log('Redirect nümunəsi');

// middleware.js
import { NextResponse } from 'next/server';

export function middleware(request) {
  if (request.nextUrl.pathname.startsWith('/admin')) {
    // Auth yoxlaması
    return NextResponse.redirect(new URL('/login', request.url));
  }
  return NextResponse.next();
}

console.log('Middleware nümunəsi');

